/// returned_value_bounded: s.last_returned = 0 ∨ s.last_returned = s.outcome_at_or_after
fn returned_value_bounded(s: &State) -> bool {
    (s.last_returned == 0) || (s.last_returned == s.outcome_at_or_after)
}

/// outcome_terminal_after_init: s.initialized = 0 ∨ (s.outcome_at_or_after ≥ 1 ∧ s.outcome_at_or_after ≤ 3)
fn outcome_terminal_after_init(s: &State) -> bool {
    (s.initialized == 0) || (((s.outcome_at_or_after >= 1) && (s.outcome_at_or_after <= 3)))
}

fn initialize(s: &mut State, target_slot: u64, outcome: u8) -> bool {
    if !(s.initialized == 0 && outcome >= 1 && outcome <= 3) {
        return false;
    }
    s.initialized = 1;
    s.target_slot = target_slot;
    s.outcome_at_or_after = outcome;
    true
}

fn resolve_case_0(s: &mut State, clock_slot: u64) -> bool {
    if !(clock_slot < s.target_slot) {
        return false;
    }
    s.last_returned = 0;
    true
}

fn resolve_otherwise(s: &mut State, clock_slot: u64) -> bool {
    if !(!(clock_slot < s.target_slot)) {
        return false;
    }
    s.last_returned = outcome_at_or_after;
    true
}

