#[derive(Debug, Clone)]
enum Op {
    Initialize(u64, u8),
    ResolveCase0(u64),
    ResolveOtherwise(u64),
}

fn arb_op() -> impl Strategy<Value = Op> {
    prop_oneof![
        (0u64..=u64::MAX, 0u8..=u8::MAX).prop_map(|(target_slot, outcome)| Op::Initialize(target_slot, outcome)),
        (0u64..=u64::MAX).prop_map(|v| Op::ResolveCase0(v)),
        (0u64..=u64::MAX).prop_map(|v| Op::ResolveOtherwise(v)),
    ]
}

fn apply_op(s: &mut State, op: &Op) -> bool {
    match op {
        Op::Initialize(target_slot, outcome) => initialize(s, *target_slot, *outcome),
        Op::ResolveCase0(clock_slot) => resolve_case_0(s, *clock_slot),
        Op::ResolveOtherwise(clock_slot) => resolve_otherwise(s, *clock_slot),
    }
}

fn assert_all_properties(s: &State, context: &str) {
    assert!(returned_value_bounded(s), "{} violated: returned_value_bounded", context);
    assert!(outcome_terminal_after_init(s), "{} violated: outcome_terminal_after_init", context);
}

